+
+        if self.json_output {
+            let output = JsonProfile {
+                name: name.to_string(),
+                left: config.left.clone(),
+                middle: config.middle.clone(),
+                right: config.right.clone(),
+            };
+            println!("{}", serde_json::to_string_pretty(&output)?);
